script:
# Minimum 3 KPIs required
if len(doc.kpis) < 3:
    frappe.throw("Minimum 3 KPIs required for a valid review.", title="Validation Error")

# Overall score must be filled before submitting
if doc.final_status == "Under Review" and doc.overall_score == 0:
    frappe.throw("Please fill KPI scores before submitting.", title="Validation Error")

# Prevent duplicate review
existing = frappe.db.exists("Performance Review", {
    "employee": doc.employee,
    "review_period": doc.review_period,
    "review_year": doc.review_year,
    "name": ["!=", doc.name]
})

if existing:
    frappe.throw(
        f"A review already exists for {doc.employee} for {doc.review_period} {doc.review_year}. Please update the existing record.",
        title="Duplicate Review"
    )
